#!/bin/bash
# Seeder params, used to inform the seeder orchestration about artifacts
# generated by each seeder. This file is sourced from both outside and
# inside chroot.
#
# Variables exported by the worker (vector/lib/seeder/worker.go) and available in
# the environment:
#
# SEEDERS_PHASES_STATE_DIR
# The path to the directory where seeders can read/write files to
# keep track of which phases have been completed. This is used by the chroot.sh scripts
# to implement idempotency and resumability.
#
# SEEDER_DONE_FLAG_FILE_PREFIX
# The prefix for the seeder done flag file, which is used by the chroot.sh scripts
# to determine if a seeder has completed its process and the chroot is in a state
# that can be used as a base for derived seeders.
#
# SEEDER_DATE_CADENCE
# The cadence at which seeder chroots are versioned. This is used to determine the
# name of the chroot directory for the seeder, and to determine when to create a new
# chroot or reuse an existing one.
#
# SEEDER_OVERLAY_GIT_REPO
# The Git repository URL for the seeder overlay, which is a repository containing the ebuilds
# and configs for the seeder. This is used by the chroot scripts to setup the
# Portage overlay for the seeder.
#
# DEFAULT_PRIVATE_GIT_REPO_PATH
# The directory path to the private git repository. This directory is expected to
# be already empty at this stage.
#
set -eu

source "${MATRIXOS_DEV_DIR}"/headers/env.include.sh
source "${MATRIXOS_DEV_DIR}"/build/seeders/common/params_lib.sh

# SEEDER_CHROOT_NAME=abc
# Name of the chroot directory that should be created by default.
# First date of the first Monday of the current week, in the past.
SEEDER_CHROOT_NAME="gnome-$(params_lib.get_chroot_date)"
if [ "${SEEDER_CHROOT_NAME}" = "gnome-" ]; then
    echo "Unable to correctly set SEEDER_CHROOT_NAME in gnome params.sh" >&2
    exit 1
fi

# SEEDER_CHROOTS_DIR=/path/to/parent/seeder/chroots/dir
# Path to the preferred chroot directory for this seeder.
SEEDER_CHROOTS_DIR="${MATRIXOS_DEV_DIR}/out/seeder/chroots"

# PREFERRED_SEEDER_CHROOT_DIR
# Path to the currently preferred chroot directory path for this seeder.
# This way you can implement a dated seeder chroot path via SEEDER_CHROOT_NAME.
PREFERRED_SEEDER_CHROOT_DIR="${SEEDER_CHROOTS_DIR}/${SEEDER_CHROOT_NAME}"

# This function can be used by other seeders to get the chroot path of the latest
# GNOME build.
gnome_params.find_latest_chroot_dir() {
    local seeder_name="${1}"
    if [ -z "${seeder_name}" ]; then
        echo "Missing parameter to find_latest_chroot_dir" >&2
        return 1
    fi

    (
        # avoid poisoning our env.
        source "${MATRIXOS_DEV_DIR}"/build/seeders/00-bedrock/params.sh
        bedrock_params.find_latest_chroot_dir_for_derived_seeder "${seeder_name}" "gnome"
    )
}

# This function can be used by other seeders to get the chroot path of ALL the
# GNOME builds.
gnome_params.find_all_chroot_dirs() {
    local seeder_name="${1}"
    (
        # avoid poisoning our env.
        source "${MATRIXOS_DEV_DIR}"/build/seeders/00-bedrock/params.sh
        bedrock_params._find_select_chroot_dirs_for_derived_seeder "${seeder_name}" "gnome" "1"
    )
}